public void lockForm()
{
    ETGRailCarLoadingTable_ds.allowEdit(false);
    ETGRailCarLoadingLineTable_ds.allowEdit(false);
    ETGRailCarLoadingLineDetails_ds.allowEdit(false);
    InventDim_ds.allowEdit(false);

    //ETGRailCarLoadingTable_ds.allowCreate(false);
    ETGRailCarLoadingLineTable_ds.allowCreate(false);
    ETGRailCarLoadingLineDetails_ds.allowCreate(false);

    ETGRailCarLoadingTable_ds.allowDelete(false);
    ETGRailCarLoadingLineTable_ds.allowDelete(false);
    ETGRailCarLoadingLineDetails_ds.allowDelete(false);

    Submit.enabled(false);
    LineDetailsFileUpload.enabled(false);
    ETGRailCarLoadingTable_ds.refresh();
    ETGRailCarLoadingLineTable_ds.refresh();
    ETGRailCarLoadingLineDetails_ds.refresh();
}

public void unlockForm()
{
    ETGRailCarLoadingTable_ds.allowEdit(true);
    ETGRailCarLoadingLineTable_ds.allowEdit(true);
    ETGRailCarLoadingLineDetails_ds.allowEdit(true);
    InventDim_ds.allowEdit(true);

    //ETGRailCarLoadingTable_ds.allowCreate(true);
    ETGRailCarLoadingLineTable_ds.allowCreate(true);
    ETGRailCarLoadingLineDetails_ds.allowCreate(true);

    ETGRailCarLoadingTable_ds.allowDelete(true);
    ETGRailCarLoadingLineTable_ds.allowDelete(true);
    ETGRailCarLoadingLineDetails_ds.allowDelete(true);

    Submit.enabled(true);
    LineDetailsFileUpload.enabled(true);
    ETGRailCarLoadingTable_ds.refresh();
    ETGRailCarLoadingLineTable_ds.refresh();
    ETGRailCarLoadingLineDetails_ds.refresh();
}

