public void updateBottomGridButtons()
{
    if (ETGRailCarLoadingTable.Submitted == NoYes::No)
    {
        boolean midHasLine = ETGRailCarLoadingLineTable_ds.cursor().RecId != 0;

        // Enable New button on bottom grid only if mid grid has a selected line
        ETGRailCarLoadingLineDetails_ds.allowCreate(midHasLine);

        // Enable Delete button on bottom grid only if a bottom line is selected
        ETGRailCarLoadingLineDetails_ds.allowDelete(
    ETGRailCarLoadingLineDetails_ds.cursor().RecId != 0 && midHasLine
                                              );
        Submit.enabled(ETGRailCarLoadingLineDetails_ds.cursor().RecId != 0 && midHasLine);
        LineDetailsFileUpload.enabled(midHasLine);

        ETGRailCarLoadingTable_ds.refresh();
        ETGRailCarLoadingLineTable_ds.refresh();
        ETGRailCarLoadingLineDetails_ds.refresh();
    }
}

/// <summary>
///
/// </summary>
/// <param name = "_append"></param>
public void create(boolean _append = false)
{
    ETGRailLoadingSerialNumber railLoadingSerialNumber;
    NumberSequenceReference numberSequenceReference;

    super(_append);

    numberSequenceReference = NumberSeqReference::findReference(extendedTypeNum(ETGRailLoadingSerialNumber));
    if (numberSequenceReference)
    {
        ttsbegin;
        railLoadingSerialNumber = NumberSeq::newGetNum(numberSequenceReference).num();
        ETGRailCarLoadingTable.ETGRailLoadingSerialNumber = railLoadingSerialNumber;
        ttscommit;
    }
}

/// <summary>
///
/// </summary>
/// <returns></returns>
public int active()
{
    int ret;

    ret = super();

    if (ETGRailCarLoadingTable.Submitted == NoYes::Yes) 
        {
            element.lockForm(); 
        }
    else 
    { 
        element.unlockForm();
    }

    // When header changes, update bottom grid button state            
    element.updateBottomGridButtons();

    return ret;
}

