/// <summary>
///
/// </summary>
public void modified()
{
    SalesLine                       salesLine;
    ETGRailCarLoadingLineTable      railLine;

    super();

    if (!ETGRailCarLoadingTable.SalesId)
return;

    ttsbegin;

    // Optional: delete existing lines for this header
    delete_from railLine
where railLine.ETGRailLoadingSerialNumber == ETGRailCarLoadingTable.ETGRailLoadingSerialNumber;

    // Loop through SalesLines
    while select crossCompany salesLine
where salesLine.SalesId == ETGRailCarLoadingTable.SalesId
    {
        railLine.clear();

        railLine.ETGRailLoadingSerialNumber = ETGRailCarLoadingTable.ETGRailLoadingSerialNumber; // header relation                   
        railLine.LineNum                    = salesLine.LineNum;
        railLine.ItemId                     = salesLine.ItemId;
        railLine.SalesQty                   = salesLine.SalesQty - salesLine.invoicedInTotal() - salesLine.deliveredInTotal()- salesLine.pickedInTotalSalesUnit()- salesLine.reservedPhysicalInSalesUnit()- salesLine.reservedOnOrderInSalesUnit();

        railLine.SalesUnit                  = salesLine.SalesUnit;
        railLine.SalesPrice                 = salesLine.SalesPrice;
        //railLine.InventDimId                = salesLine.InventDimId;

        // IMPORTANT: copy InventDimId directly
        InventDim sourceDim, targetDim;

        // Read InventDim from the source company 
        changecompany(salesLine.dataAreaId) 
        {   
            sourceDim = InventDim::find(salesLine.InventDimId); 
        }

        // Copy values into target buffer
        targetDim = sourceDim; 

        // Create or find matching InventDim in the current company 
        targetDim = InventDim::findOrCreate(targetDim);
        railLine.InventDimId   = targetDim.InventDimId;

        railLine.insert();
    }

    ttscommit;

    // Refresh line datasource
    ETGRailCarLoadingLineTable_ds.research();


}

