public void modified()
{
    ETGRailCarLoadingLineTable      railLine        = ETGRailCarLoadingLineTable_ds.cursor();

    super();
    ETGCanadaParameters                     CanadaParameters    = ETGCanadaParameters::find();

    // IMPORTANT: copy InventDimId directly
    InventDim sourceDim, targetDim;  

    if (CanadaParameters.DefaultEntityForDocuments)
    {
        // Read InventDim from the source company
        changecompany(CanadaParameters.DefaultEntityForDocuments)
        {
            sourceDim = InventDim::find(InventTable::getInventDimId(ETGRailCarLoadinglineTable.ItemId));
        }
    }
    else 
    {
        sourceDim = InventDim::find(InventTable::getInventDimId(ETGRailCarLoadinglineTable.ItemId));
    }

    // Copy values into target buffer
    targetDim = sourceDim;

    // Create or find matching InventDim in the current company
    targetDim = InventDim::findOrCreate(targetDim);
    railLine.InventDimId   = targetDim.InventDimId;
    //railLine.update();


}

/// <summary>
///
/// </summary>
/// <param name = "_formControl"></param>
/// <param name = "_filterStr"></param>
public void lookup(FormControl _formControl, str _filterStr)
{
    ETGCanadaParameters                     CanadaParameters    = ETGCanadaParameters::find();
    // Run your custom lookup instead of the default one 

    if (CanadaParameters.DefaultEntityForDocuments)
    {
        SysTableLookup          lookup = SysTableLookup::newParameters(tableNum(InventTable), _formControl);
        Query                   query  = new Query();
        query.allowCrossCompany(true);
        QueryBuildDataSource    qbds;

        lookup.addLookupfield(fieldNum(InventTable, ItemId));
        lookup.addlookupmethod(tableMethodStr(InventTable, itemName));
        lookup.addLookupfield(fieldNum(InventTable, dataAreaId)); // show company

        qbds = query.addDataSource(tableNum(InventTable));
        query.addCompanyRange(CanadaParameters.DefaultEntityForDocuments);

        lookup.parmQuery(query);
        lookup.performFormLookup();
    }
    else 
    {
        super(_formControl, _filterStr);
    }
}

