/// <summary>
///
/// </summary>
/// <param name = "_formControl"></param>
/// <param name = "_filterStr"></param>
public void lookup(FormControl _formControl, str _filterStr)
{
    ETGCanadaParameters                     CanadaParameters    = ETGCanadaParameters::find();
    if (CanadaParameters.DefaultEntityForDocuments)
    {
        changecompany(CanadaParameters.DefaultEntityForDocuments)
        {

            if (!ETGRailCarLoadingLineTable.ItemId)
            {
                warning("Select an item first.");
                return;
            }

            SysTableLookup          lookup = SysTableLookup::newParameters(tableNum(InventBatch), _formControl);
            Query                   query  = new Query();
            QueryBuildDataSource    qbds;
            //query.allowCrossCompany(true);

            // Fields to show in lookup
            lookup.addLookupField(fieldNum(InventBatch, inventBatchId));
            lookup.parmUseLookupValue(false);

            // Build query
            qbds = query.addDataSource(tableNum(InventBatch));
            qbds.addRange(fieldNum(InventBatch, ItemId)).value(queryValue(ETGRailCarLoadingLineTable.ItemId));
            // qbds.addRange(fieldNum(InventBatch, DataAreaId)).value(queryValue(CanadaParameters.DefaultEntityForDocuments));

            lookup.parmQuery(query);
            lookup.performFormLookup();
        }
    }
}

