/// <summary>
///
/// </summary>
/// <returns></returns>
public boolean validateWrite()
{
    boolean ret;

    ret = super();

    ETGRailCarLoadingLineTable line =
        ETGRailCarLoadingLineTable::find(ETGRailCarLoadingLineDetails.ETGRailLoadingSerialNumber, ETGRailCarLoadingLineDetails.LineNum);

    if (!line.RecId)
return ret;

    ETGCanadaParameters                     CanadaParameters    = ETGCanadaParameters::find();
    InventTableModule     inventTableModule;

    if (CanadaParameters.DefaultEntityForDocuments)
    {
        // Read InventDim from the source company
        changecompany(CanadaParameters.DefaultEntityForDocuments)
        {

            // Fetch item for over-delivery %
            inventTableModule = InventTableModule::find(line.ItemId,ModuleInventPurchSales::sales);
        }
    }

    // Open qty = ordered - delivered
    real openQty = line.SalesQty;

    // Over-delivery %

    real overPct;
    if (inventTableModule.recid)
    {
        overPct = inventTableModule.OverDeliveryPct;
    }

    // Allowed qty
    real allowedQty = openQty + (openQty * overPct / 100);

    // SUM all loaded qty for this SAME sales line across ALL rail loads
    ETGRailCarLoadingLineDetails details;
    real totalLoaded = 0;

    select sum(Qty) from details
where details.ETGRailLoadingSerialNumber == line.ETGRailLoadingSerialNumber
  && details.LineNum == line.LineNum
  && details.RecId != ETGRailCarLoadingLineDetails.RecId;   // exclude current line

    totalLoaded = details.Qty; // SUM result is stored in the field buffer

    // Add current line qty
    real newTotal = totalLoaded + ETGRailCarLoadingLineDetails.Qty;

    // Validate
    if (newTotal > allowedQty)
    {
        error(strFmt(
    "Total loaded quantity %1 exceeds allowed quantity %2 for Sales Line %3 ",
    newTotal,
    allowedQty,
    line.LineNum));

        ret = false;
    }

    return ret;
}

