/// <summary>
///
/// </summary>
public void clicked()
{
    super();


    ETGCanadaParameters parameters = ETGCanadaParameters::find();

    if (!parameters.DefaultEntityForDocuments)
    {
        warning("Default entity is not defined.");
        return;
    }

    InventJournalId  journalId =
    ETGRailCarTransferJournalService::createTransferJournal(
        ETGRailCarLoadingTable,
        parameters.DefaultEntityForDocuments);

    info(strFmt("Transfer journal %1 created in company %2.",
            journalId,
            parameters.DefaultEntityForDocuments));

    // Mark record as submitted ttsbegin;
    ttsbegin;
    ETGRailCarLoadingTable.Submitted = NoYes::Yes;
    ETGRailCarLoadingTable.update(); 
    ttscommit; 
    // Lock the form for this record 
    element.lockForm();
}

/// <summary>
///
/// </summary>
public void lookup()
{  
    ETGCanadaParameters                     CanadaParameters    = ETGCanadaParameters::find();

    if (CanadaParameters.DefaultEntityForDocuments)
    {
        Query query = new Query();
        query.allowCrossCompany(true);
        QueryBuildDataSource queryBuildDataSource;

        queryBuildDataSource = query.addDataSource(tableNum(SalesTable));
        queryBuildDataSource.addRange(fieldNum(SalesTable,SalesStatus)) .value(queryValue(enum2Str(SalesStatus::Backorder)));

        SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(SalesTable), this); 
        sysTableLookup.addLookupField(fieldNum(SalesTable, SalesId));
        sysTableLookup.addLookupField(fieldNum(SalesTable, CustAccount));
        sysTableLookup.addLookupMethod(tableMethodStr(SalesTable,customerName));

        query.addCompanyRange(CanadaParameters.DefaultEntityForDocuments);

        sysTableLookup.parmQuery(query);

        sysTableLookup.performFormLookup();
    }


}

